    uint32_t blockDim = (totalTiles < MAX_BLOCK_DIM) ? totalTiles : MAX_BLOCK_DIM;
    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_C(C);
    tiling.set_inputH(inputH);
    tiling.set_inputW(inputW);
    tiling.set_outputH(outputH);
